35	            message: e.message,
36	            data: {
37	              stack: e.stack,
38	            },
39	          },
40	          id: json.id,
41	        })
42	      }
43	    }
44	
45	    if (json.method === 'getManifest') {
46	      if (handler.onManifest) {
47	        try {
48	          const manifest = await handler.onManifest(json.params)
49	          respond({
50	            jsonrpc: '2.0',
51	            result: {
52	              manifest,
53	            },
54	            id: json.id,
55	          })
56	        } catch (_e) {
57	          const e = _e as Error
58	          respond({
59	            jsonrpc: '2.0',
60	            error: {
61	              code: -32000,
62	              message: e.message,
63	              data: {
64	                stack: e.stack,
65	              },
66	            },
67	            id: json.id,
68	          })
69	        }
70	      } else {
71	        respond({
72	          jsonrpc: '2.0',
73	          result: {
74	            manifest: null,
75	          },
76	          id: json.id,
77	        })
78	      }
79	    }
80	  })
81	
82	  process.stdin.resume()
83	}
84	
85	function respond(response: JsonRpc.Response): void {
86	  process.stderr.write(JSON.stringify(response) + '\n')
87	}
