# Plan: `packages/generator-rest-client/` — Typed REST API Client Generator

## Context

The goal is to add a new Prisma generator package that reads the DMMF (Data Model Meta Format) from a Prisma schema and emits a single `rest-client.ts` file containing typed TypeScript interfaces for every model plus a REST client class per model with `findMany`, `findUnique`, `create`, `update`, and `delete` methods. A root `RestApiClient` aggregates all per-model clients into one entry point.

Users configure it in their `prisma.config.ts`/schema like any other generator:

```prisma
generator restClient {
  provider = "prisma-generator-rest-client"
  output   = "./generated/rest-client"
}
```

---

## Critical Files to Create

```
packages/generator-rest-client/
├── package.json
├── tsconfig.json
├── tsconfig.build.json
├── helpers/
│   └── build.ts
└── src/
    ├── index.ts       ← entry point + generatorHandler wiring
    ├── generator.ts   ← DMMF parsing + file writing
    └── template.ts    ← pure string-template helpers
```

One root-level file also needs a **path alias** addition:
- `tsconfig.build.bundle.json` → add `@prisma/generator-rest-client` entry under `compilerOptions.paths`

---

## Step-by-Step Implementation

### Step 1 — `package.json`

Follow the pattern of `packages/generator-helper/package.json` (minimal deps, workspace references, `bin` entry for the Prisma runner).

```json
{
  "name": "@prisma/generator-rest-client",
  "version": "0.0.0",
  "description": "Prisma generator that produces a typed REST API client from a schema",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "bin": {
    "prisma-generator-rest-client": "dist/index.js"
  },
  "exports": {
    ".": {
      "require": { "types": "./dist/index.d.ts",  "default": "./dist/index.js"  },
      "import":  { "types": "./dist/index.d.mts", "default": "./dist/index.mjs" }
    }
  },
  "license": "Apache-2.0",
  "repository": { "type": "git", "url": "https://github.com/prisma/prisma.git",
                  "directory": "packages/generator-rest-client" },
  "dependencies": {
    "@prisma/dmmf":             "workspace:*",
    "@prisma/generator-helper": "workspace:*"
  },
  "devDependencies": {
    "@types/node": "~20.19.24",
    "typescript": "5.4.5"
  },
  "scripts": {
    "dev":             "DEV=true tsx helpers/build.ts",
    "build":           "tsx helpers/build.ts",
    "prepublishOnly":  "pnpm run build"
  },
  "files": ["dist"],
  "sideEffects": false
}
```

Key decisions:
- `bin` maps `"prisma-generator-rest-client"` → `dist/index.js` so Prisma can find and spawn it by the provider name.
- Only `@prisma/dmmf` (DMMF type definitions) and `@prisma/generator-helper` (protocol wiring) are needed as runtime deps.

### Step 2 — `tsconfig.json`

Identical to `packages/generator-helper/tsconfig.json`:

```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```

### Step 3 — `tsconfig.build.json`

Identical to `packages/generator-helper/tsconfig.build.json`:

```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist",
    "rootDir": "src"
  },
  "include": ["src"]
}
```

### Step 4 — `helpers/build.ts`

Uses `adapterConfig` (bundles to CJS + ESM with types) — same as `packages/client-generator-ts/helpers/build.ts`:

```typescript
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

### Step 5 — `src/template.ts`

Pure helpers that take DMMF data and return TypeScript code strings. No side-effects.

```typescript
import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar/enum/relation field to a TypeScript type string. */
export function tsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'object') {
    base = field.type  // relation → referenced model name
  } else if (field.kind === 'enum') {
    base = field.type  // enum → enum type name
  } else {
    // scalar mapping
    switch (field.type) {
      case 'String':   base = 'string';     break
      case 'Boolean':  base = 'boolean';    break
      case 'Int':
      case 'Float':
      case 'Decimal':  base = 'number';     break
      case 'BigInt':   base = 'bigint';     break
      case 'DateTime': base = 'Date';       break
      case 'Json':     base = 'unknown';    break
      case 'Bytes':    base = 'Uint8Array'; break
      default:         base = 'unknown';
    }
  }
  if (field.isList)     base = `${base}[]`
  if (!field.isRequired) base = `${base} | null`
  return base
}

/** Lowercases the first character of a string (for property names). */
export function camelCase(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

/** Generates the `export interface ModelName { ... }` block for a model. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')  // skip relation fields in the interface
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${tsType(f)}`)
    .join('\n')
  return `export interface ${model.name} {\n${fields}\n}`
}

/** Generates the `export interface ModelNameWhereUniqueInput { ... }` block. */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) return ''
  return (
    `export interface ${model.name}WhereUniqueInput {\n` +
    `  ${idField.name}: ${tsType({ ...idField, isRequired: true, isList: false })}\n` +
    `}`
  )
}

/** Generates the REST client class for a single model. */
export function renderRestClientClass(model: DMMF.Model): string {
  const name = model.name
  const idField = model.fields.find((f) => f.isId)
  const idParam = idField ? `args.where.${idField.name}` : 'undefined'
  const resource = camelCase(name) + 's'  // naive pluralisation

  return `\
export class ${name}RestClient {
  constructor(private readonly request: RequestFn, private readonly baseUrl: string = '') {}

  async findMany(args?: { where?: Partial<${name}>; take?: number; skip?: number }): Promise<${name}[]> {
    return this.request(\`\${this.baseUrl}/${resource}\`, 'GET') as Promise<${name}[]>
  }

  async findUnique(args: { where: ${name}WhereUniqueInput }): Promise<${name} | null> {
    return this.request(\`\${this.baseUrl}/${resource}/\${${idParam}}\`, 'GET') as Promise<${name} | null>
  }

  async create(args: { data: Omit<${name}, '${idField?.name ?? 'id'}'> }): Promise<${name}> {
    return this.request(\`\${this.baseUrl}/${resource}\`, 'POST', args.data) as Promise<${name}>
  }

  async update(args: { where: ${name}WhereUniqueInput; data: Partial<${name}> }): Promise<${name}> {
    return this.request(\`\${this.baseUrl}/${resource}/\${${idParam}}\`, 'PUT', args.data) as Promise<${name}>
  }

  async delete(args: { where: ${name}WhereUniqueInput }): Promise<${name}> {
    return this.request(\`\${this.baseUrl}/${resource}/\${${idParam}}\`, 'DELETE') as Promise<${name}>
  }
}`
}

/** Generates the root `RestApiClient` class that aggregates all model clients. */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const props = models
    .map((m) => `  readonly ${camelCase(m.name)}: ${m.name}RestClient`)
    .join('\n')
  const assigns = models
    .map((m) => `    this.${camelCase(m.name)} = new ${m.name}RestClient(requestFn, baseUrl)`)
    .join('\n')
  return `\
export class RestApiClient {
${props}

  constructor(requestFn: RequestFn, baseUrl: string = '') {
${assigns}
  }
}`
}
```

### Step 6 — `src/generator.ts`

Orchestrates generation: reads DMMF, assembles output, writes `rest-client.ts` to the configured output directory.

```typescript
import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator-helper'

import {
  renderModelInterface,
  renderRestClientClass,
  renderRootClient,
  renderWhereUniqueInput,
} from './template'

const FILE_HEADER = `\
// This file was auto-generated by @prisma/generator-rest-client.
// Do not edit it manually.

/** Minimal HTTP request function signature the REST clients depend on. */
type RequestFn = (path: string, method: string, body?: unknown) => Promise<unknown>

`

export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('generator-rest-client: no output path configured')
  }

  const models = options.dmmf.datamodel.models

  const sections: string[] = [FILE_HEADER]

  for (const model of models) {
    sections.push(renderModelInterface(model))
    sections.push('')
    const whereUnique = renderWhereUniqueInput(model)
    if (whereUnique) {
      sections.push(whereUnique)
      sections.push('')
    }
  }

  for (const model of models) {
    sections.push(renderRestClientClass(model))
    sections.push('')
  }

  sections.push(renderRootClient(models))
