import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
function prismaScalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Bytes':
      return 'Uint8Array'
    case 'Decimal':
      return 'string'
    case 'Json':
      return 'unknown'
    default:
      return 'unknown'
  }
}

/** Converts a Prisma field to its TypeScript type annotation string. */
function fieldToTs(field: DMMF.Field): string {
  let tsType: string
  if (field.kind === 'scalar') {
    tsType = prismaScalarToTs(field.type)
  } else if (field.kind === 'enum') {
    tsType = field.type
  } else {
    tsType = 'unknown'
  }
  if (field.isList) {
    tsType = `${tsType}[]`
  }
  return field.isRequired ? tsType : `${tsType} | null`
}

/** Returns the scalar and enum fields of a model, filtering out relation fields. */
function scalarAndEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/** Returns the id and unique scalar fields for use in a WhereUniqueInput type. */
function uniqueFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => (f.isId || f.isUnique) && f.kind === 'scalar')
}

/** Lowercases the first character of a string. */
function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Renders the `export interface` block for a model's scalar and enum fields. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  const lines = fields.map((f) => `  ${f.name}: ${fieldToTs(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/** Renders the `WhereUniqueInput` type alias used for lookup operations. */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const fields = uniqueFields(model)
  if (fields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }
  const lines = fields.map((f) => `  ${f.name}?: ${prismaScalarToTs(f.type)}`)
  return `export type ${model.name}WhereUniqueInput = {\n${lines.join('\n')}\n}`
}

/** Renders the REST client class for a model with typed CRUD methods. */
export function renderRestClientClass(model: DMMF.Model): string {
  const name = model.name
  const resourcePath = `/${lowerFirst(name)}`
  return `export class ${name}RestClient {
  constructor(private readonly request: RequestFn) {}

  findMany(): Promise<${name}[]> {
    return this.request('GET', '${resourcePath}') as Promise<${name}[]>
  }

  findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const key = Object.keys(where)[0]
    const value = Object.values(where)[0]
    return this.request('GET', \`${resourcePath}/\${key}/\${value}\`) as Promise<${name} | null>
  }

  create(data: Omit<${name}, 'id'>): Promise<${name}> {
    return this.request('POST', '${resourcePath}', data) as Promise<${name}>
  }

  update(where: ${name}WhereUniqueInput, data: Partial<${name}>): Promise<${name}> {
    const key = Object.keys(where)[0]
    const value = Object.values(where)[0]
    return this.request('PATCH', \`${resourcePath}/\${key}/\${value}\`, data) as Promise<${name}>
  }

  delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const key = Object.keys(where)[0]
    const value = Object.values(where)[0]
    return this.request('DELETE', \`${resourcePath}/\${key}/\${value}\`) as Promise<${name}>
  }
}`
}

/**
 * Renders the root `RestApiClient` class that aggregates all per-model clients
 * and exposes them as named properties.
 */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const propDecls = models.map((m) => `  readonly ${lowerFirst(m.name)}: ${m.name}RestClient`)
  const assignments = models.map((m) => `    this.${lowerFirst(m.name)} = new ${m.name}RestClient(request)`)
  return `export class RestApiClient {
${propDecls.join('\n')}

  constructor(request: RequestFn) {
${assignments.join('\n')}
  }
}`
}

/**
 * The file header prepended to every generated `rest-client.ts`.
 * Includes the do-not-edit notice and the shared `RequestFn` type alias.
 */
export const FILE_HEADER = `// Generated by @prisma/generator-rest-client. Do not edit manually.

export type RequestFn = (method: string, path: string, body?: unknown) => Promise<unknown>`

